var selectedEmployee=0,succMsg="Successfully Deleted！",noticeStartDiv="<div id='message-green'><table border='0' width='100%' cellpadding='0' cellspacing='0'><tr><td class='green-left'>",noticeEndDiv="</td><td class='green-right'><a class='close-green'><img src='"+rootUri+"Content/Images/icon_close_green.gif' alt='' /></a></td></tr></table></div>";function DeleteSelectedItems(){var a=$(":checkbox[id!=checkAllRecords]:checked");if(a.length<1){alert("Please select more than 1 records");return false}confirm("Really delete these records?")&&$.ajax({type:"POST",url:rootUri+"QueueStatus/_DeleteSelectedItems",dataType:"json",data:a,success:onSuccess,error:onError});return false}function onSuccess(a){if(a.success=="True"){var b=$("#tlqueue").data("tGrid");b.rebind();$("#result").empty();$("#result").hide().append(noticeStartDiv+succMsg+noticeEndDiv).slideDown("slow");$(".close-green").click(function(){$("#message-green").fadeOut("slow")})}return false}function onComplete(){}function onError(a){alert("Error! Status = "+a.status)}function isAlphanumeric(a){return!/[^a-zA-Z0-9]/.test(a)};